import { LeavePolicy, CreateLeavePolicyDto, UpdateLeavePolicyDto } from '../../shared/types/index';
import { ILeavePolicyRepository } from './policy.repository';
import { IAuditService } from '../../shared/audit/audit.service';

export interface IPolicyService {
  getPolicy(id: string): Promise<LeavePolicy | null>;
  getActivePolicies(): Promise<LeavePolicy[]>;
  getPolicyByLeaveType(leaveTypeId: string): Promise<LeavePolicy | null>;
  createPolicy(dto: CreateLeavePolicyDto): Promise<LeavePolicy>;
  updatePolicy(id: string, dto: UpdateLeavePolicyDto): Promise<LeavePolicy>;
  deletePolicy(id: string): Promise<void>;
  validateEntitlement(
    employeeId: string,
    leaveTypeId: string,
    requestedDays: number,
    fiscalYear: number,
    remainingBalance: number
  ): Promise<{ valid: boolean; reason?: string }>;
}

export class PolicyService implements IPolicyService {
  constructor(
    private readonly policyRepository: ILeavePolicyRepository,
    private readonly auditService: IAuditService
  ) {}

  async getPolicy(id: string): Promise<LeavePolicy | null> {
    return this.policyRepository.findById(id);
  }

  async getActivePolicies(): Promise<LeavePolicy[]> {
    return this.policyRepository.findActive();
  }

  async getPolicyByLeaveType(leaveTypeId: string): Promise<LeavePolicy | null> {
    return this.policyRepository.findByLeaveType(leaveTypeId);
  }

  async createPolicy(dto: CreateLeavePolicyDto): Promise<LeavePolicy> {
    const policy = await this.policyRepository.create(dto);
    await this.auditService.createAuditRecord({
      entityType: 'LeavePolicy',
      entityId: policy.id,
      action: 'CREATE',
      newValues: policy,
      performedBy: dto.performedBy,
    });
    return policy;
  }

  async updatePolicy(id: string, dto: UpdateLeavePolicyDto): Promise<LeavePolicy> {
    const policy = await this.policyRepository.update(id, dto);
    await this.auditService.createAuditRecord({
      entityType: 'LeavePolicy',
      entityId: id,
      action: 'UPDATE',
      oldValues: dto.oldValues,
      newValues: policy,
      performedBy: dto.performedBy,
    });
    return policy;
  }

  async deletePolicy(id: string): Promise<void> {
    await this.policyRepository.delete(id);
    await this.auditService.createAuditRecord({
      entityType: 'LeavePolicy',
      entityId: id,
      action: 'DELETE',
      performedBy: 'system',
    });
  }

  async validateEntitlement(
    employeeId: string,
    leaveTypeId: string,
    requestedDays: number,
    fiscalYear: number,
    remainingBalance: number
  ): Promise<{ valid: boolean; reason?: string }> {
    const policy = await this.policyRepository.findByLeaveType(leaveTypeId);
    if (!policy || !policy.is_active) {
      return { valid: false, reason: 'Leave policy not found or inactive' };
    }
    if (requestedDays > remainingBalance) {
      return { valid: false, reason: 'Insufficient leave balance' };
    }
    return { valid: true };
  }
}","File: src/modules/policy/policy.controller.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import { z } from 'zod';
import { IPolicyService } from './policy.service';
import { CreateLeavePolicyDto, UpdateLeavePolicyDto } from '../../shared/types/index';

const createPolicySchema = z.object({
  policy_name: z.string().min(1),
  leave_type: z.enum(['annual', 'sick', 'emergency', 'unpaid', 'maternity', 'paternity']),
  entitlement_days: z.number().min(0),
  accrual_rate: z.number().optional(),
  max_accumulation: z.number().min(0).optional(),
  minimum_notice_days: z.number().int().min(0).optional(),
  requires_manager_approval: z.boolean().default(true),
  is_active: z.boolean().default(true),
});

const updatePolicySchema = z.object({
  policy_name: z.string().min(1).optional(),
  leave_type: z.enum(['annual', 'sick', 'emergency', 'unpaid', 'maternity', 'paternity']).optional(),
  entitlement_days: z.number().min(0).optional(),
  accrual_rate: z.number().optional(),
  max_accumulation: z.number().min(0).optional(),
  minimum_notice_days: z.number().int().min(0).optional(),
  requires_manager_approval: z.boolean().optional(),
  is_active: z.boolean().optional(),
});

const paramsSchema = z.object({
  id: z.string().uuid(),
});

export class PolicyController {
  constructor(private readonly policyService: IPolicyService) {}

  async getPolicy(request: FastifyRequest, reply: FastifyReply) {
    const { id } = paramsSchema.parse(request.params);
    const policy = await this.policyService.getPolicy(id);
    if (!policy) {
      return reply.status(404).send({ error: 'Policy not found' });
    }
    return reply.send(policy);
  }

  async getPolicies(request: FastifyRequest, reply: FastifyReply) {
    const policies = await this.policyService.getActivePolicies();
    return reply.send(policies);
  }

  async createPolicy(request: FastifyRequest, reply: FastifyReply) {
    const dto = createPolicySchema.parse(request.body) as CreateLeavePolicyDto;
    const policy = await this.policyService.createPolicy(dto);
    return reply.status(201).send(policy);
  }

  async updatePolicy(request: FastifyRequest, reply: FastifyReply) {
    const { id } = paramsSchema.parse(request.params);
    const dto = updatePolicySchema.parse(request.body) as UpdateLeavePolicyDto;
    const policy = await this.policyService.updatePolicy(id, dto);
    return reply.send(policy);
  }
}","File: src/modules/policy/policy.routes.ts
import { FastifyInstance, FastifyPluginOptions } from 'fastify';
import { PolicyController } from './policy.controller';
import { IPolicyService } from './policy.service';
import { rbacMiddleware } from '../../shared/middleware/rbac';

export async function policyRoutes(
  fastify: FastifyInstance,
  options: FastifyPluginOptions & { policyService: IPolicyService }
) {
  const controller = new PolicyController(options.policyService);

  fastify.get('/policies/:id', {
    preHandler: [rbacMiddleware('read:policy')],
  }, controller.getPolicy.bind(controller));

  fastify.get('/policies', {
    preHandler: [rbacMiddleware('read:policy')],
  }, controller.getPolicies.bind(controller));

  fastify.post('/policies', {
    preHandler: [rbacMiddleware('create:policy')],
  }, controller.createPolicy.bind(controller));

  fastify.put('/policies/:id', {
    preHandler: [rbacMiddleware('update:policy')],
  }, controller.updatePolicy.bind(controller));
